import json
import boto3
from botocore.exceptions import ClientError

# Initialize Secrets Manager client
secrets_client = boto3.client('secretsmanager', region_name='us-east-1')

def get_secret(secret_name):
    """
    Retrieve secret from AWS Secrets Manager with caching
    """
    try:
        response = secrets_client.get_secret_value(SecretId=secret_name)

        # Parse secret string (JSON format)
        if 'SecretString' in response:
            return json.loads(response['SecretString'])
        else:
            # Binary secret
            return response['SecretBinary']

    except ClientError as e:
        if e.response['Error']['Code'] == 'ResourceNotFoundException':
            print(f"Secret {secret_name} not found")
        elif e.response['Error']['Code'] == 'InvalidRequestException':
            print(f"Invalid request for secret {secret_name}")
        elif e.response['Error']['Code'] == 'InvalidParameterException':
            print(f"Invalid parameter for secret {secret_name}")
        else:
            print(f"Error retrieving secret: {e}")
        raise e

def lambda_handler(event, context):
    """
    Lambda function handler with Secrets Manager integration
    """
    # Retrieve database credentials from Secrets Manager
    db_secret = get_secret('prod/database/credentials')

    # Extract individual credentials
    db_host = db_secret['host']
    db_username = db_secret['username']
    db_password = db_secret['password']
    db_name = db_secret['database']

    # Retrieve API key for third-party service
    api_secret = get_secret('prod/api/stripe')
    stripe_api_key = api_secret['api_key']

    # Use credentials securely (example: database connection)
    import psycopg2

    try:
        conn = psycopg2.connect(
            host=db_host,
            database=db_name,
            user=db_username,
            password=db_password,
            connect_timeout=5
        )

        # Execute database operations
        cursor = conn.cursor()
        cursor.execute('SELECT version();')
        db_version = cursor.fetchone()

        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Successfully connected to database',
                'version': db_version[0]
            })
        }

    except Exception as e:
        print(f"Database connection error: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Database connection failed'})
        }
    finally:
        if conn:
            conn.close()

